import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const Projects = () => {
  const { user } = useContext(AuthContext);
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    startDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const response = await api.get('/projects');
      setProjects(response.data.projects || []);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching projects:', error);
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.post('/projects', formData);
      setShowForm(false);
      setFormData({ name: '', description: '', startDate: new Date().toISOString().split('T')[0] });
      fetchProjects();
    } catch (error) {
      alert(error.response?.data?.message || 'Error creating project');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this project?')) return;

    try {
      await api.delete(`/projects/${id}`);
      fetchProjects();
    } catch (error) {
      alert(error.response?.data?.message || 'Error deleting project');
    }
  };

  if (loading) {
    return <div className="loading">Loading projects...</div>;
  }

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h1>Projects</h1>
        {user.role === 'PM' && (
          <button onClick={() => setShowForm(!showForm)} className="btn btn-primary">
            {showForm ? 'Cancel' : 'New Project'}
          </button>
        )}
      </div>

      {showForm && user.role === 'PM' && (
        <div className="card">
          <h3>Create New Project</h3>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Project Name</label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                required
              />
            </div>
            <div className="form-group">
              <label>Description</label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label>Start Date</label>
              <input
                type="date"
                value={formData.startDate}
                onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
                required
              />
            </div>
            <button type="submit" className="btn btn-primary">Create Project</button>
          </form>
        </div>
      )}

      {projects.length === 0 ? (
        <div className="card">
          <p>No projects found. {user.role === 'PM' && 'Create your first project!'}</p>
        </div>
      ) : (
        <div className="grid">
          {projects.map(project => (
            <div key={project._id} className="card">
              <h3>{project.name}</h3>
              <p>{project.description || 'No description'}</p>
              <div style={{ marginTop: '15px' }}>
                <p><strong>Team Members:</strong> {project.teamMembers?.length || 0}</p>
                <p>
                  <strong>Risk Level:</strong>{' '}
                  <span className={`risk-${project.riskLevel?.toLowerCase()}`}>
                    {project.riskLevel || 'Low'}
                  </span>
                </p>
                {project.riskScore > 0 && (
                  <p><strong>Risk Score:</strong> {project.riskScore}/100</p>
                )}
              </div>
              <div style={{ marginTop: '15px', display: 'flex', gap: '10px' }}>
                <Link to={`/projects/${project._id}`} className="btn btn-primary">
                  View Details
                </Link>
                {user.role === 'PM' && (
                  <>
                    <Link to={`/metrics/${project._id}`} className="btn btn-secondary">
                      Metrics
                    </Link>
                    <button
                      onClick={() => handleDelete(project._id)}
                      className="btn btn-danger"
                    >
                      Delete
                    </button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Projects;
